const focusableSelector = [
  "a[href]",
  "button:not([disabled])",
  "textarea:not([disabled])",
  "input:not([disabled])",
  "select:not([disabled])",
  "[tabindex]:not([tabindex='-1'])",
].join(",");

export function getFocusableElements(container: HTMLElement) {
  return Array.from(container.querySelectorAll<HTMLElement>(focusableSelector))
    .filter((element) => !element.hasAttribute("disabled"))
    .filter((element) => element.getAttribute("aria-hidden") !== "true");
}

export function focusInitialElement(container: HTMLElement) {
  const firstFocusable = getFocusableElements(container)[0] ?? container;
  firstFocusable.focus();
}

export function trapFocus(container: HTMLElement, event: KeyboardEvent) {
  if (event.key !== "Tab") {
    return;
  }

  const focusableElements = getFocusableElements(container);

  if (focusableElements.length === 0) {
    event.preventDefault();
    container.focus();
    return;
  }

  const firstElement = focusableElements[0];
  const lastElement = focusableElements[focusableElements.length - 1];
  const activeElement = document.activeElement;

  if (event.shiftKey && activeElement === firstElement) {
    event.preventDefault();
    lastElement.focus();
    return;
  }

  if (!event.shiftKey && activeElement === lastElement) {
    event.preventDefault();
    firstElement.focus();
  }
}

import {
  Children,
  cloneElement,
  forwardRef,
  isValidElement,
  type CSSProperties,
  type HTMLAttributes,
  type ReactElement,
  type ReactNode,
  type Ref,
} from "react";
import clsx, { type ClassValue } from "clsx";

// create the swirski tone system
export type SwirskiTone =
  | "default"
  | "muted"
  | "subtle"
  | "inverted"
  | "blue"
  | "yellow"
  | "red"
  | "white"
  | "black";

// create the swirski size system
export type SwirskiSize = "xs" | "sm" | "md" | "lg" | "xl" | "display";

// create the swirski variant system
export type SwirskiVariant =
  | "solid"
  | "outline"
  | "soft"
  | "ghost"
  | "plain"
  | "default";

export type SwirskiSystemProps<
  Variant extends string = SwirskiVariant,
  Size extends string = SwirskiSize,
  Tone extends string = SwirskiTone,
> = {
  className?: string;
  variant?: Variant;
  size?: Size;
  tone?: Tone;
};

export type SwirskiPolymorphicProps = {
  asChild?: boolean;
  children?: ReactNode;
};
// combines class names
export function cn(...inputs: ClassValue[]) {
  return clsx(...inputs);
}
// apply swirski data attributes to component
export function swirskiAttrs(
  component: string,
  options: {
    size?: string;
    tone?: string;
    variant?: string;
  } = {},
) {
  return {
    "data-swirski-component": component,
    "data-swirski-size": options.size,
    "data-swirski-tone": options.tone,
    "data-swirski-variant": options.variant,
  };
}
// compose the refs so that refs and passed refs will work together
export function composeRefs<T>(...refs: Array<Ref<T> | undefined>) {
  return (node: T | null) => {
    refs.forEach((ref) => {
      if (!ref) {
        return;
      }

      if (typeof ref === "function") {
        ref(node);
        return;
      }

      ref.current = node;
    });
  };
}

function isEventHandler(key: string, value: unknown) {
  return /^on[A-Z]/.test(key) && typeof value === "function";
}

function mergeSlotProps(
  slotProps: HTMLAttributes<HTMLElement>,
  childProps: HTMLAttributes<HTMLElement>,
) {
  const mergedProps = { ...slotProps, ...childProps };

  for (const key of Object.keys(childProps)) {
    const slotValue = slotProps[key as keyof HTMLAttributes<HTMLElement>];
    const childValue = childProps[key as keyof HTMLAttributes<HTMLElement>];

    if (isEventHandler(key, slotValue) && isEventHandler(key, childValue)) {
      mergedProps[key as keyof HTMLAttributes<HTMLElement>] = ((
        event: unknown,
      ) => {
        (childValue as (event: unknown) => void)(event);
        (slotValue as (event: unknown) => void)(event);
      }) as never;
    }
  }

  return {
    ...mergedProps,
    className: cn(slotProps.className, childProps.className),
    style: {
      ...(slotProps.style as CSSProperties | undefined),
      ...(childProps.style as CSSProperties | undefined),
    },
  };
}

export type SlotProps = HTMLAttributes<HTMLElement> & {
  children?: ReactNode;
};

export const Slot = forwardRef<HTMLElement, SlotProps>(
  ({ children, ...props }, forwardedRef) => {
    const child = Children.only(children);

    if (!isValidElement(child)) {
      throw new Error("Swirski asChild expects a single valid React element.");
    }

    const childElement = child as ReactElement<HTMLAttributes<HTMLElement>>;
    const childRef = (childElement.props as { ref?: Ref<HTMLElement> }).ref;

    return cloneElement(childElement, {
      ...mergeSlotProps(props, childElement.props),
      ref: composeRefs(forwardedRef, childRef),
    } as HTMLAttributes<HTMLElement> & { ref: Ref<HTMLElement> });
  },
);

Slot.displayName = "Slot";

"use client";

import { useEffect, useState } from "react";

export function usePortalRoot() {
  const [portalRoot, setPortalRoot] = useState<HTMLElement | null>(null);

  useEffect(() => {
    setPortalRoot(document.body);
  }, []);

  return portalRoot;
}

"use client";

import { CSSProperties, HTMLAttributes, ReactNode, createContext, useContext } from "react";
import clsx from "clsx";

export type SwirskiColorScheme = "light" | "dark";

export type SwirskiThemeTokens = {
  colorInk: string;
  colorPaper: string;
  colorSurface: string;
  colorMuted: string;
  colorBlue: string;
  colorYellow: string;
  colorRed: string;
  colorWhite: string;
  colorBlack: string;
  colorShadow: string;
  colorFocus: string;
  borderWidth: string;
  shadowSm: string;
  shadowMd: string;
  shadowLg: string;
  fontBody: string;
  fontHeading: string;
  fontDisplay: string;
};

export type SwirskiTheme = Partial<SwirskiThemeTokens> & {
  cssVariables?: Record<string, string>;
};

export type SwirskiProviderProps = {
  children: ReactNode;
  colorScheme?: SwirskiColorScheme;
  theme?: SwirskiTheme;
} & HTMLAttributes<HTMLDivElement>;

const defaultTokens: SwirskiThemeTokens = {
  colorInk: "#0B0B0C",
  colorPaper: "#F5F5F3",
  colorSurface: "#FFFFFF",
  colorMuted: "rgba(11, 11, 12, 0.68)",
  colorBlue: "#0057FF",
  colorYellow: "#FFD400",
  colorRed: "#FF3131",
  colorWhite: "#FFFFFF",
  colorBlack: "#0B0B0C",
  colorShadow: "#0B0B0C",
  colorFocus: "#0057FF",
  borderWidth: "4px",
  shadowSm: "3px 3px 0 var(--sw-color-shadow)",
  shadowMd: "6px 6px 0 var(--sw-color-shadow)",
  shadowLg: "10px 10px 0 var(--sw-color-shadow)",
  fontBody: "var(--font-inter, system-ui, sans-serif)",
  fontHeading: "var(--font-anton, Impact, sans-serif)",
  fontDisplay: "var(--font-bangers, Impact, fantasy)",
};

const darkTokens: Partial<SwirskiThemeTokens> = {
  colorInk: "#F7F7F2",
  colorPaper: "#121212",
  colorSurface: "#1D1D1F",
  colorMuted: "rgba(247, 247, 242, 0.68)",
  colorWhite: "#1D1D1F",
  colorBlack: "#F7F7F2",
  colorShadow: "#FFD400",
  colorFocus: "#FFD400",
};

const tokenVariables: Record<keyof SwirskiThemeTokens, string> = {
  colorInk: "--sw-color-ink",
  colorPaper: "--sw-color-paper",
  colorSurface: "--sw-color-surface",
  colorMuted: "--sw-color-muted",
  colorBlue: "--sw-color-blue",
  colorYellow: "--sw-color-yellow",
  colorRed: "--sw-color-red",
  colorWhite: "--sw-color-white",
  colorBlack: "--sw-color-black",
  colorShadow: "--sw-color-shadow",
  colorFocus: "--sw-color-focus",
  borderWidth: "--sw-border-width",
  shadowSm: "--sw-shadow-sm",
  shadowMd: "--sw-shadow-md",
  shadowLg: "--sw-shadow-lg",
  fontBody: "--sw-font-body",
  fontHeading: "--sw-font-heading",
  fontDisplay: "--sw-font-display",
};

const SwirskiThemeContext = createContext<SwirskiThemeTokens>(defaultTokens);

export const swirskiDefaultTheme = defaultTokens;
export const swirskiDarkTheme = { ...defaultTokens, ...darkTokens };

function resolveTheme(
  colorScheme: SwirskiColorScheme,
  theme?: SwirskiTheme,
): SwirskiThemeTokens {
  const schemeTokens =
    colorScheme === "dark" ? swirskiDarkTheme : swirskiDefaultTheme;

  return {
    ...schemeTokens,
    ...theme,
  };
}

function themeToStyle(theme: SwirskiThemeTokens, extra?: SwirskiTheme) {
  const style: Record<string, string> = {};

  Object.entries(tokenVariables).forEach(([tokenName, variableName]) => {
    style[variableName] = theme[tokenName as keyof SwirskiThemeTokens];
  });

  Object.entries(extra?.cssVariables ?? {}).forEach(([name, value]) => {
    style[name] = value;
  });

  return style as CSSProperties;
}

export function createSwirskiTheme(theme: SwirskiTheme) {
  return theme;
}

export function SwirskiProvider({
  children,
  className,
  colorScheme = "light",
  style,
  theme,
  ...props
}: SwirskiProviderProps) {
  const resolvedTheme = resolveTheme(colorScheme, theme);

  return (
    <SwirskiThemeContext.Provider value={resolvedTheme}>
      <div
        className={clsx(
          "swirski-provider min-h-full bg-[var(--sw-color-paper)] text-[var(--sw-color-ink)]",
          className,
        )}
        data-swirski-color-scheme={colorScheme}
        style={{ ...themeToStyle(resolvedTheme, theme), ...style }}
        {...props}
      >
        {children}
      </div>
    </SwirskiThemeContext.Provider>
  );
}

export function useSwirskiTheme() {
  return useContext(SwirskiThemeContext);
}

export {
  SwirskiProvider,
  createSwirskiTheme,
  swirskiDarkTheme,
  swirskiDefaultTheme,
  useSwirskiTheme,
} from "./SwirskiProvider";
export type {
  SwirskiColorScheme,
  SwirskiProviderProps,
  SwirskiTheme,
  SwirskiThemeTokens,
} from "./SwirskiProvider";

@import "tailwindcss";

@import "@fontsource/anton";
@import "@fontsource/bangers";

:root,
[data-swirski-color-scheme="light"] {
  --sw-color-ink: #0b0b0c;
  --sw-color-paper: #f5f5f3;
  --sw-color-surface: #ffffff;
  --sw-color-muted: rgba(11, 11, 12, 0.68);
  --sw-color-blue: #0057ff;
  --sw-color-yellow: #ffd400;
  --sw-color-red: #ff3131;
  --sw-color-white: #ffffff;
  --sw-color-black: #0b0b0c;
  --sw-color-shadow: #0b0b0c;
  --sw-color-focus: #0057ff;
  --sw-border-width: 4px;
  --sw-shadow-sm: 3px 3px 0 var(--sw-color-shadow);
  --sw-shadow-md: 6px 6px 0 var(--sw-color-shadow);
  --sw-shadow-lg: 10px 10px 0 var(--sw-color-shadow);
  --sw-font-body: var(--font-inter, system-ui, sans-serif);
  --sw-font-heading: var(--font-anton, "Anton", sans-serif);
  --sw-font-display: var(--font-bangers, "Bangers", cursive);
}

[data-swirski-color-scheme="dark"] {
  --sw-color-ink: #f7f7f2;
  --sw-color-paper: #121212;
  --sw-color-surface: #1d1d1f;
  --sw-color-muted: rgba(247, 247, 242, 0.68);
  --sw-color-white: #1d1d1f;
  --sw-color-black: #f7f7f2;
  --sw-color-shadow: #ffd400;
  --sw-color-focus: #ffd400;
}

.swirski-provider {
  min-height: 100%;
  background: var(--sw-color-paper);
  color: var(--sw-color-ink);
  font-family: var(--sw-font-body);
}

@theme inline {
  --font-anton: "Anton", sans-serif;
  --font-bangers: "Bangers", cursive;
}
